build_history_response:
const req = $items('Validate Input', 0, 0)[0].json;
const requestedPage = Number(req.page ?? 1);
const requestedPageSize = Number(req.page_size ?? 25);
const page = Number.isInteger(requestedPage) && requestedPage > 0 ? requestedPage : 1;
const pageSize = Number.isInteger(requestedPageSize) && requestedPageSize > 0 ? Math.min(requestedPageSize, 100) : 25;

const from = String(req.from ?? '').trim();
const to = String(req.to ?? '').trim();
const resultFilter = String(req.result ?? '').trim().toLowerCase();
const runModeFilter = String(req.run_mode ?? '').trim().toLowerCase();
const executionFilter = String(req.execution_id ?? '').trim();
const correlationFilter = String(req.correlation_id_filter ?? req.correlation_id_query ?? '').trim();

const parseTs = (value) => {
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const fromDate = from ? parseTs(from) : null;
const toDate = to ? parseTs(to) : null;
let rows = items.map((item) => item.json || {});

rows = rows.filter((row) => {
  const ts = parseTs(row.requested_at ?? row.timestamp ?? row.executed_at ?? '');
  if (fromDate && (!ts || ts < fromDate)) return false;
  if (toDate && (!ts || ts > toDate)) return false;

  const rowResult = String(row.status ?? row.result ?? '').trim().toLowerCase();
  const rowRunMode = String(row.run_mode ?? '').trim().toLowerCase();
  const rowExecutionId = String(row.execution_id ?? '').trim();
  const rowCorrelationId = String(row.correlation_id ?? '').trim();

  if (resultFilter && rowResult !== resultFilter) return false;
  if (runModeFilter && rowRunMode !== runModeFilter) return false;
  if (executionFilter && rowExecutionId !== executionFilter) return false;
  if (correlationFilter && rowCorrelationId !== correlationFilter) return false;

  return true;
});

rows.sort((a, b) => String(b.requested_at ?? b.timestamp ?? '').localeCompare(String(a.requested_at ?? a.timestamp ?? '')));

const total = rows.length;
const start = (page - 1) * pageSize;
const itemsPage = rows.slice(start, start + pageSize).map((row) => ({
  execution_id: String(row.execution_id ?? ''),
  tracking_id: String(row.tracking_id ?? ''),
  correlation_id: String(row.correlation_id ?? ''),
  action: String(row.action ?? ''),
  run_mode: String(row.run_mode ?? ''),
  result: String(row.status ?? row.result ?? ''),
  actor: String(row.actor ?? ''),
  executed_at: String(row.requested_at ?? row.timestamp ?? row.executed_at ?? ''),
}));

return [{
  json: {
    page,
    page_size: pageSize,
    total,
    items: itemsPage,
  },
}];
